const rows = $items().map(item => item.json);

if (rows.length === 0) {
  return [{ json: { emailHtml: '<p>No results.</p>' } }];
}

// Group rows by bucket (top_5_wow, top_10_mrpi_value, etc.)
const groups = {};
for (const row of rows) {
  const b = row.bucket || 'Unbucketed';
  if (!groups[b]) groups[b] = [];
  groups[b].push(row);
}

// Format a cell, with metric-aware logic:
// - GRS/WSC: value_current = $
// - MRPI:    value_current = %
// - wow_change & metric_share: % for all metrics
function formatCell(key, row) {
  const value = row[key];
  if (value === null || value === undefined || value === '') return '';

  const num = Number(value);

  // value_current: currency for GRS/WSC, percent for MRPI
  if (key === 'value_current' && !isNaN(num)) {
    if (row.metric === 'MRPI') {
      // assumes 0.25 = 25%
      return (num * 100).toFixed(2) + '%';
    } else {
      return new Intl.NumberFormat('en-US', {
        style: 'currency',
        currency: 'USD',
        maximumFractionDigits: 2,
      }).format(num);
    }
  }

  // % for WoW + Share (all metrics)
  if ((key === 'wow_change' || key === 'metric_share') && !isNaN(num)) {
    // assumes 0.12 = 12%
    return (num * 100).toFixed(1) + '%';
  }

  return value;
}

// Use all keys from first row, but drop bucket from visible columns
const allHeaders = Object.keys(rows[0]);
const headersToShow = allHeaders.filter(h => h !== 'bucket');

const sections = [];

for (const [bucketName, bucketRows] of Object.entries(groups)) {
  const firstRow = bucketRows[0];

  const headerLabels = {
    metric: 'Metric',
    supplier_id: 'Supplier ID',
    supplier_name: 'Supplier',
    value_current:
      firstRow.metric === 'MRPI'
        ? 'MRPI'
        : firstRow.metric || 'Value',
    wow_change: 'WoW',
    metric_share: 'Share',
  };

  const headerHtml = headersToShow
    .map(h => `<th>${headerLabels[h] || h}</th>`)
    .join('');

  const bodyRowsHtml = bucketRows
    .map(r =>
      `<tr>${headersToShow
        .map(h => `<td>${formatCell(h, r)}</td>`)
        .join('')}</tr>`
    )
    .join('');

  const tableHtml = `
    <h2>${bucketName}</h2>
    <table border="1" cellpadding="4" cellspacing="0">
      <thead><tr>${headerHtml}</tr></thead>
      <tbody>${bodyRowsHtml}</tbody>
    </table>
  `;

  sections.push(tableHtml);
}

const emailHtml = sections.join('\n<hr/>\n');

return [{ json: { emailHtml } }];

