function money(value, options = {}) {
  if (value === null || value === undefined || value === "N/A") return "N/A";
  const num = Number(value);
  const sign = num < 0 ? "-" : options.showPlus && num > 0 ? "+" : "";
  return sign + "$" + Math.abs(num).toLocaleString("en-US", {
    minimumFractionDigits: 0,
    maximumFractionDigits: 0
  });
}

function number(value, options = {}) {
  if (value === null || value === undefined || value === "N/A") return "N/A";
  const num = Number(value);
  const sign = num < 0 ? "-" : options.showPlus && num > 0 ? "+" : "";
  return sign + Math.abs(num).toLocaleString("en-US", {
    minimumFractionDigits: 0,
    maximumFractionDigits: 0
  });
}

function percent(value, options = {}) {
  if (value === null || value === undefined || value === "N/A") return "N/A";
  const num = Number(value);
  const sign = num < 0 ? "-" : options.showPlus && num > 0 ? "+" : "";
  return sign + (Math.abs(num) * 100).toFixed(1) + "%";
}

function escapeHtml(value) {
  if (value === null || value === undefined) return "";
  return String(value)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;");
}

function colorizeChange(value, formatted) {
  if (formatted === "N/A") return formatted;

  const num = Number(value);
  if (Number.isNaN(num) || num === 0) return formatted;

  const color = num > 0 ? "#1a7f37" : "#d1242f";
  return `<span style="color: ${color}; font-weight: 600;">${formatted}</span>`;
}

function formatCell(row, key) {
  const value = row[key];

  if (key.includes("pct")) {
    return colorizeChange(value, percent(value, { showPlus: true }));
  }

  if (key.includes("change")) {
    if (key.includes("grs")) {
      return colorizeChange(value, money(value, { showPlus: true }));
    }

    if (key.includes("visits")) {
      return colorizeChange(value, number(value, { showPlus: true }));
    }

    return colorizeChange(value, percent(value, { showPlus: true }));
  }

  if (key.includes("cvr")) return percent(value);
  if (key.includes("availability")) return percent(value);
  if (key.includes("mrpi")) return percent(value);
  if (key.includes("wsi")) return percent(value);

  if (key.includes("grs")) return money(value);
  if (key.includes("visits")) return number(value);

  return escapeHtml(value);
}

function makeTable(title, rows, columns) {
  if (!Array.isArray(rows) || rows.length === 0) {
    return `
      <h2>${escapeHtml(title)}</h2>
      <p><em>No results found.</em></p>
    `;
  }

  const headerHtml = columns.map(function(col) {
    return `<th>${escapeHtml(col.label)}</th>`;
  }).join("");

  const bodyHtml = rows.map(function(row) {
    const cells = columns.map(function(col) {
      return `<td>${formatCell(row, col.key)}</td>`;
    }).join("");

    return `<tr>${cells}</tr>`;
  }).join("");

  return `
    <h2>${escapeHtml(title)}</h2>
    <table>
      <thead>
        <tr>${headerHtml}</tr>
      </thead>
      <tbody>
        ${bodyHtml}
      </tbody>
    </table>
  `;
}

